import React, { useState } from 'react';
import { View, StyleSheet, FlatList } from 'react-native';
import { Text, Card, SegmentedButtons, Chip } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';

export default function OrdersScreen() {
  const [filter, setFilter] = useState('all');

  const orders = [
    {
      id: 1,
      orderNumber: 'ORD-2024-001',
      date: '2024-01-28',
      farmer: 'Rajesh Kumar',
      products: [
        { name: 'Fresh Tomatoes', quantity: 2, price: 80 },
        { name: 'Organic Spinach', quantity: 1, price: 30 },
      ],
      total: 110,
      status: 'Delivered',
      deliveryDate: '2024-01-29',
    },
    {
      id: 2,
      orderNumber: 'ORD-2024-002',
      date: '2024-01-30',
      farmer: 'Priya Sharma',
      products: [
        { name: 'Fresh Carrots', quantity: 3, price: 105 },
      ],
      total: 105,
      status: 'In Transit',
      estimatedDelivery: '2024-01-31',
    },
    {
      id: 3,
      orderNumber: 'ORD-2024-003',
      date: '2024-01-31',
      farmer: 'Amit Patil',
      products: [
        { name: 'Fresh Apples', quantity: 2, price: 240 },
      ],
      total: 240,
      status: 'Processing',
      estimatedDelivery: '2024-02-01',
    },
  ];

  const filteredOrders = orders.filter((order) => {
    if (filter === 'all') return true;
    if (filter === 'active')
      return order.status === 'Processing' || order.status === 'In Transit';
    if (filter === 'completed') return order.status === 'Delivered';
    return true;
  });

  const getStatusColor = (status) => {
    switch (status) {
      case 'Delivered':
        return { bg: '#E8F5E9', text: '#2E7D32' };
      case 'In Transit':
        return { bg: '#E3F2FD', text: '#1976D2' };
      case 'Processing':
        return { bg: '#FFF3E0', text: '#F57C00' };
      default:
        return { bg: '#F5F5F5', text: '#666' };
    }
  };

  const renderOrder = ({ item }) => {
    const statusColor = getStatusColor(item.status);
    return (
      <Card style={styles.orderCard}>
        <View style={styles.orderHeader}>
          <View>
            <Text style={styles.orderNumber}>{item.orderNumber}</Text>
            <Text style={styles.orderDate}>{item.date}</Text>
          </View>
          <View
            style={[styles.statusBadge, { backgroundColor: statusColor.bg }]}
          >
            <Text style={[styles.statusText, { color: statusColor.text }]}>
              {item.status}
            </Text>
          </View>
        </View>

        <View style={styles.farmerInfo}>
          <Icon name="account" size={16} color="#666" />
          <Text style={styles.farmerName}> {item.farmer}</Text>
        </View>

        <View style={styles.productsContainer}>
          {item.products.map((product, index) => (
            <View key={index} style={styles.productRow}>
              <Text style={styles.productName}>
                {product.name} x {product.quantity}
              </Text>
              <Text style={styles.productPrice}>₹{product.price}</Text>
            </View>
          ))}
        </View>

        <View style={styles.orderFooter}>
          <View>
            <Text style={styles.totalLabel}>Total Amount</Text>
            <Text style={styles.totalAmount}>₹{item.total}</Text>
          </View>
          {item.status !== 'Delivered' && (
            <View style={styles.deliveryInfo}>
              <Icon name="clock-outline" size={14} color="#666" />
              <Text style={styles.deliveryText}>
                {' '}
                Expected: {item.estimatedDelivery}
              </Text>
            </View>
          )}
        </View>
      </Card>
    );
  };

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>My Orders</Text>
        <Text style={styles.orderCount}>{filteredOrders.length} orders</Text>
      </View>

      <View style={styles.filterContainer}>
        <SegmentedButtons
          value={filter}
          onValueChange={setFilter}
          buttons={[
            { value: 'all', label: 'All' },
            { value: 'active', label: 'Active' },
            { value: 'completed', label: 'Completed' },
          ]}
        />
      </View>

      <FlatList
        data={filteredOrders}
        renderItem={renderOrder}
        keyExtractor={(item) => item.id.toString()}
        contentContainerStyle={styles.listContainer}
        ListEmptyComponent={
          <View style={styles.emptyContainer}>
            <Icon name="clipboard-list-outline" size={60} color="#ccc" />
            <Text style={styles.emptyText}>No orders found</Text>
          </View>
        }
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  header: {
    backgroundColor: '#fff',
    padding: 20,
    paddingTop: 60,
    elevation: 2,
  },
  headerTitle: {
    fontSize: 24,
    fontWeight: 'bold',
    color: '#333',
  },
  orderCount: {
    fontSize: 14,
    color: '#666',
    marginTop: 5,
  },
  filterContainer: {
    padding: 20,
    backgroundColor: '#fff',
  },
  listContainer: {
    paddingBottom: 20,
  },
  orderCard: {
    marginHorizontal: 20,
    marginBottom: 15,
    elevation: 2,
    padding: 15,
  },
  orderHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'flex-start',
    marginBottom: 10,
  },
  orderNumber: {
    fontSize: 16,
    fontWeight: 'bold',
    color: '#333',
  },
  orderDate: {
    fontSize: 12,
    color: '#666',
    marginTop: 3,
  },
  statusBadge: {
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 12,
  },
  statusText: {
    fontSize: 12,
    fontWeight: '600',
  },
  farmerInfo: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 15,
  },
  farmerName: {
    fontSize: 14,
    color: '#666',
  },
  productsContainer: {
    backgroundColor: '#f9f9f9',
    borderRadius: 8,
    padding: 10,
    marginBottom: 15,
  },
  productRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    paddingVertical: 5,
  },
  productName: {
    fontSize: 14,
    color: '#333',
  },
  productPrice: {
    fontSize: 14,
    color: '#666',
  },
  orderFooter: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'flex-end',
  },
  totalLabel: {
    fontSize: 12,
    color: '#666',
  },
  totalAmount: {
    fontSize: 20,
    fontWeight: 'bold',
    color: '#2E7D32',
    marginTop: 3,
  },
  deliveryInfo: {
    flexDirection: 'row',
    alignItems: 'center',
  },
  deliveryText: {
    fontSize: 12,
    color: '#666',
  },
  emptyContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    marginTop: 100,
  },
  emptyText: {
    fontSize: 16,
    color: '#999',
    marginTop: 10,
  },
});
